def vex_reply_filter(sender, recipient, msg):
    """Vex validation filter for AutoGen replies"""

    # Skip non-extraction messages
    if "Invoice" not in msg.get("content", ""):
        return True

    result = vex_client.verify(
        data=msg["content"],
        verifiers=["extraction_schema", "field_accuracy"],
        context={"document": document_text}
    )

    if not result.valid:
        print(f"Vex blocked: {result.issues}")
        return False  # Block invalid reply

    return True

# Register filter
groupchat.register_reply([None, None], reply_filter=vex_reply_filter)
